module A2_poly_reducer128 (
   input  wire [2*128-2:0] x,
   output wire [  128-1:0] y
   );

localparam [(128)*(128 - 1) - 1:0]  M = {
   16256'
   }; //JLPL - 10_21_25

genvar i, j;

for (i=0; i<128; i=i+1) begin : gen_y
   wire [128 - 2:0] terms;
   for (j=0; j<128-1; j=j+1) begin : gen_t
      assign terms[j] = x[128+j] & M[i*(128-1)+j];
      end
   assign y[i] = x[i] ^ (^terms);
   end

endmodule
